173→/// Cross-model judge that invokes GPT 5.4 via Codex CLI.
174→pub struct Judge<E: CommandExecutor = TokioExecutor> {
175→    codex_cmd: String,
176→    model: String,
177→    executor: E,
178→}
179→
180→impl Judge<TokioExecutor> {
181→    /// Create a new judge with the default `TokioExecutor`.
182→    pub fn new() -> Self {
183→        Self {
184→            codex_cmd: "codex".to_string(),
185→            model: "gpt-5.4-xhigh".to_string(),
186→            executor: TokioExecutor,
187→        }
188→    }
189→}
190→
191→impl<E: CommandExecutor> Judge<E> {
192→    /// Create a judge with a custom executor (for testing).
193→    pub fn with_executor(executor: E) -> Self {
194→        Self {
195→            codex_cmd: "codex".to_string(),
196→            model: "gpt-5.4-xhigh".to_string(),
197→            executor,
198→        }
199→    }
200→
201→    /// Evaluate specialist findings against ground truth using the cross-model judge.
202→    ///
203→    /// Retry semantics:
204→    /// - On CLI failure: retries once, then falls back (2 attempts total).
205→    /// - On CLI success but parse failure: falls back immediately (no retry).
206→    pub async fn evaluate(
207→        &self,
208→        code_sample: &str,
209→        expected_json: &str,
210→        specialist_findings_json: &str,
211→        finding_ids: &[String],
212→    ) -> Result<JudgeResult> {
213→        let prompt = build_judge_prompt(code_sample, expected_json, specialist_findings_json);
214→        let args = vec![
215→            "--model".to_string(),
216→            self.model.clone(),
217→            "--quiet".to_string(),
218→            "--json".to_string(),
219→            "-p".to_string(),
220→            prompt,
221→        ];
222→
223→        // Attempt 1
224→        match self.executor.execute(&self.codex_cmd, &args).await {
225→            Ok(output) => {
226→                if let Ok(result) = parse_judge_response(&output) {
227→                    return Ok(result);
228→                }
229→                // Parse failure: no retry, fall back immediately
230→                return Ok(JudgeResult::fallback(finding_ids));
231→            }
232→            Err(e) => {
233→                tracing::warn!("judge attempt 1 failed: {:#}", e);
234→            }
235→        }
236→
237→        // Attempt 2 (retry on CLI failure)
238→        match self.executor.execute(&self.codex_cmd, &args).await {
239→            Ok(output) => {
240→                if let Ok(result) = parse_judge_response(&output) {
241→                    return Ok(result);
242→                }
243→                Ok(JudgeResult::fallback(finding_ids))
244→            }
245→            Err(e) => {
246→                tracing::warn!("judge attempt 2 failed: {:#}", e);
247→                Ok(JudgeResult::fallback(finding_ids))
248→            }
249→        }
250→    }
251→}
