  1→//! Benchmark types and loader for autoresearch specialist evaluation.
  2→//!
  3→//! Reads benchmark cases from `.forge/autoresearch/benchmarks/<specialist>/<case-name>/`
  4→//! directories, each containing `code.rs`, `context.md`, and `expected.json`.
  5→
  6→use std::path::Path;
  7→
  8→use anyhow::{Context, Result};
  9→use serde::{Deserialize, Serialize};
 10→
 11→/// A finding that a specialist is expected to detect.
 12→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
 13→pub struct ExpectedFinding {
 14→    pub id: String,
 15→    pub severity: String,
 16→    pub description: String,
 17→    pub location: String,
 18→}
 19→
 20→/// A pattern that a specialist must NOT flag (false-positive guard).
 21→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
 22→pub struct MustNotFlag {
 23→    pub id: String,
 24→    pub description: String,
 25→    #[serde(default)]
 26→    pub location: Option<String>,
 27→}
 28→
 29→/// Expected outcomes for a benchmark case.
 30→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
 31→pub struct Expected {
 32→    pub must_find: Vec<ExpectedFinding>,
 33→    pub must_not_flag: Vec<MustNotFlag>,
 34→}
 35→
 36→/// A single benchmark case loaded from a directory.
 37→#[derive(Debug, Clone)]
 38→pub struct BenchmarkCase {
 39→    pub name: String,
 40→    pub code: String,
 41→    pub context: String,
 42→    pub expected: Expected,
 43→}
 44→
 45→/// A collection of benchmark cases for a specific specialist.
 46→#[derive(Debug, Clone)]
 47→pub struct BenchmarkSuite {
 48→    pub specialist: String,
 49→    pub cases: Vec<BenchmarkCase>,
 50→}
 51→
 52→impl BenchmarkCase {
 53→    /// Load a benchmark case from a directory containing `code.rs`, `context.md`, and `expected.json`.
 54→    ///
 55→    /// The case name is derived from the directory's basename.
 56→    pub fn load(dir: &Path) -> Result<Self> {
 57→        let name = dir
 58→            .file_name()
 59→            .context("no directory name")?
 60→            .to_string_lossy()
 61→            .to_string();
 62→
 63→        let code = std::fs::read_to_string(dir.join("code.rs"))
 64→            .with_context(|| format!("Failed to read code.rs in benchmark '{}'", name))?;
 65→
 66→        let context = std::fs::read_to_string(dir.join("context.md"))
 67→            .with_context(|| format!("Failed to read context.md in benchmark '{}'", name))?;
 68→
 69→        let expected_str = std::fs::read_to_string(dir.join("expected.json"))
 70→            .with_context(|| format!("Failed to read expected.json in benchmark '{}'", name))?;
 71→
 72→        let expected: Expected = serde_json::from_str(&expected_str)
 73→            .with_context(|| format!("Failed to parse expected.json in benchmark '{}'", name))?;
 74→
 75→        Ok(Self {
 76→            name,
 77→            code,
 78→            context,
 79→            expected,
 80→        })
 81→    }
 82→}
 83→
 84→impl BenchmarkSuite {
 85→    /// Load all benchmark cases for a specialist from `.forge/autoresearch/benchmarks/<specialist>/`.
 86→    ///
 87→    /// Returns an empty suite if the directory doesn't exist or is empty.
 88→    /// Cases are sorted by name for deterministic ordering.
 89→    pub fn load(forge_dir: &Path, specialist: &str) -> Result<Self> {
 90→        let benchmarks_dir = forge_dir
 91→            .join("autoresearch")
 92→            .join("benchmarks")
 93→            .join(specialist);
 94→
 95→        if !benchmarks_dir.exists() {
 96→            return Ok(Self {
 97→                specialist: specialist.to_string(),
 98→                cases: Vec::new(),
 99→            });
100→        }
101→
102→        let mut entries: Vec<_> = std::fs::read_dir(&benchmarks_dir)
103→            .with_context(|| {
104→                format!(
105→                    "Failed to read benchmarks directory for specialist '{}'",
106→                    specialist
107→                )
108→            })?
109→            .filter_map(|e| e.ok())
110→            .filter(|e| e.path().is_dir())
111→            .collect();
112→
113→        entries.sort_by_key(|e| e.file_name());
114→
115→        let cases = entries
116→            .iter()
117→            .map(|e| BenchmarkCase::load(&e.path()))
118→            .collect::<Result<Vec<_>>>()?;
119→
120→        Ok(Self {
121→            specialist: specialist.to_string(),
122→            cases,
123→        })
124→    }
125→
126→    /// Returns the list of known specialist types.
127→    pub fn specialist_names() -> &'static [&'static str] {
128→        &["security", "performance", "architecture", "simplicity"]
129→    }
130→}
