        })
        .count();
    let precision = if total_findings == 0 {
        1.0
    } else {
        1.0 - false_positives as f64 / total_findings as f64
    };

    let composite = 0.4 * recall + 0.3 * precision + 0.3 * actionability;

    SpecialistScore {
        recall,
        precision,
        actionability,
