        };

        let findings = vec![
            // Finding 0: matches must_find (not novel, not FP)
            Finding {
                severity: "high".into(),
                file: "code.rs".into(),
                line: Some(12),
                issue: "race condition detected in query execution".into(),
                suggestion: "".into(),
