        ];

        // Judge classifies: 0=TP, 1=TP (but must_not_flag overrides), 2=FP
        let judge = make_judge_result(
            vec![
                ("0", ClassificationVerdict::TruePositive),
                ("1", ClassificationVerdict::TruePositive),
                ("2", ClassificationVerdict::FalsePositive),
