        );

        let score = Scorer::score(&findings, &expected, Some(&judge));
        // FPs: 1 from must_not_flag + 1 from judge on novel = 2 total
        // 3 findings total => precision = 1.0 - 2/3 ≈ 0.333
        assert!(
